// Validate + normalize the inbound payload, then look up the magnet config.
//
// Payload shape (from packages/ui-funnel/EmailCaptureCard + packages/email-gate):
//   { email, magnet, source, tool?, utm_source?, utm_medium?, utm_campaign?, ts? }
//
// Returns one of:
//   { json: { ok: true, ...normalized, config } }   -> proceed to fan-out
//   { json: { ok: false, status: 400, reason } }     -> short-circuit to error response

const body = $input.first().json.body || $input.first().json || {};
const email = (body.email || '').toString().trim().toLowerCase();
const magnet = (body.magnet || '').toString().trim();
const source = (body.source || '').toString().trim();
const tool = (body.tool || '').toString().trim();

// RFC-light email check. Reject obvious garbage; IS does the strict validation downstream.
const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
if (!emailOk) {
  return [{ json: { ok: false, status: 400, reason: 'invalid_email', received: email } }];
}
if (!magnet) {
  return [{ json: { ok: false, status: 400, reason: 'missing_magnet' } }];
}

// === MAGNET DISPATCH TABLE ===
// IS segmentation is via the `magnet:<slug>` TAG applied in the
// AddUpdateLead call downstream — IS automations listen for those tags
// and dispatch the right drip sequence. No list_id needed.
//
// `pdf_url` is the link emailed to the subscriber. Set `pdf_hosted: true`
// only when the URL actually exists on production — until then, the
// fallback messaging promises a manual follow-up so the user isn't sent
// a dead link.
//
// Add a new entry whenever a new lead magnet ships. The form's `magnet`
// value must match a key here, or the router falls through to FALLBACK.
const MAGNETS = {
  'strhost-lodging-tax-report': {
    pdf_url: 'https://strhost.tools/pdfs/strhost-lodging-tax-quickstart.pdf',
    pdf_hosted: false,
    email_subject: 'Your STR lodging-tax quick-start'
  },
  'strops-cleaner-sop': {
    pdf_url: 'https://strops.tools/pdfs/cleaner-sop.pdf',
    pdf_hosted: false,
    email_subject: 'Your STR cleaner SOP template'
  },
  'strops-maintenance-checklist': {
    pdf_url: 'https://strops.tools/pdfs/maintenance-checklist.pdf',
    pdf_hosted: false,
    email_subject: 'Your STR maintenance checklist'
  },
  'strops-supply-par-level': {
    pdf_url: 'https://strops.tools/pdfs/supply-par-level.pdf',
    pdf_hosted: false,
    email_subject: 'Your STR supply par-level worksheet'
  },
  'strguests-template-pack': {
    pdf_url: 'https://strguests.tools/pdfs/guest-template-pack.zip',
    pdf_hosted: false,
    email_subject: 'Your guest message template pack'
  },
  'strbuyers-disclosures-checklist': {
    pdf_url: 'https://strbuyers.tools/pdfs/disclosures-checklist.pdf',
    pdf_hosted: false,
    email_subject: 'Your STR disclosures checklist'
  },
  'strbuyers-buyer-playbook': {
    pdf_url: 'https://strbuyers.tools/pdfs/buyer-playbook.pdf',
    pdf_hosted: false,
    email_subject: 'Your STR buyer playbook'
  },
  'strledger-47-deductions': {
    pdf_url: 'https://thestrledger.com/pdfs/47-deductions.pdf',
    pdf_hosted: false,
    email_subject: 'Your 47 STR deductions guide'
  }
};

const FALLBACK = {
  pdf_url: null,
  pdf_hosted: false,
  email_subject: 'Thanks for subscribing to STR Ledger'
};

const config = MAGNETS[magnet] || FALLBACK;
const unknownMagnet = config === FALLBACK;

// Render the body now so the SMTP node sends a literal string.
let rendered_body;
if (config.pdf_hosted && config.pdf_url) {
  rendered_body = `Here is your resource:\n\n${config.pdf_url}\n\nNo spam. One email per resource you grab. Reply if you need anything.\n\n— Daniel`;
} else if (unknownMagnet) {
  rendered_body = `Thanks for signing up. We did not recognize the lead magnet \`${magnet}\` — a human will look at this within a day and send the right resource manually. You can reply to this email if you expected something specific.`;
} else {
  // Known magnet but PDF not yet hosted — honest manual-follow-up message.
  rendered_body = `Thanks for requesting the ${magnet} resource. We're finishing the file this week and will email it to you the moment it's ready. (If you need it sooner, reply to this email and a human will get it to you.)\n\n— Daniel`;
}

return [{
  json: {
    ok: true,
    status: 200,
    email,
    magnet,
    source,
    tool,
    utm_source: body.utm_source || '',
    utm_medium: body.utm_medium || '',
    utm_campaign: body.utm_campaign || '',
    ts: body.ts || new Date().toISOString(),
    config: {
      pdf_url: config.pdf_url,
      pdf_hosted: config.pdf_hosted,
      email_subject: config.email_subject,
      email_body: rendered_body,
      unknown_magnet: unknownMagnet
    }
  }
}];
